mapper.select:
SELECT /* BondMgmtMapper.selectSoldAssetListEx */ B.CONTRACT_NUM , B.SUB_LINK_NAME , FN_GET_CODENM('RCP001', B.CUSTOMER_TYPE) AS CUSTOMER_TYPE , DECODE(B.CUSTOMER_TYPE, 'I', SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN),0,6), '') AS USER_SSN , B.TAX_ID , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS ORGN_NM , B.SUB_ADR_PRIMARY_LN , B.SUBSCRIBER_NO , TO_CHAR(ADD_MONTHS(TO_DATE(B.INST_STRT_DATE, 'YYYYMMDD'), 1), 'YYYY-MM')||'-01' AS PAY_STRT_DT , TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(B.INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYY-MM-DD') AS PAY_END_DT , '매월말일' AS REDEEM_DT , F_GET_KT_CODE_NM('MSP_JUO_BAN_INFO', 'BL_BILLING_METHOD', B.BL_BILLING_METHOD) AS BL_BILLING_METHOD , B.TTL_INST_AMNT , 0 AS INST_INT_AMT , 0 AS INST_ETC_AMT , B.TTL_INST_AMNT + 0 + 0 AS INST_TOTAL_AMT , (SELECT YET_PYMN_AMNT FROM MSP_BOND_ASSET WHERE GRNT_INSR_MNGM_NO = A.GRNT_INSR_MNGM_NO AND BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SALE_YM,'YYYYMM'),-1),'YYYYMM') AND A.RTN_YM IS NULL ) AS BOND_SALE_AMT , 0 AS BOND_SALE_INT_AMT , 0 AS BOND_SALE_ETC_AMT , (SELECT YET_PYMN_AMNT FROM MSP_BOND_ASSET WHERE GRNT_INSR_MNGM_NO = A.GRNT_INSR_MNGM_NO AND BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SALE_YM,'YYYYMM'),-1),'YYYYMM') AND A.RTN_YM IS NULL ) + 0 + 0 AS BOND_SALE_TOTAL_AMT , B.YET_PYMN_AMNT , TRUNC(B.TTL_INST_AMNT/B.TTL_INST_MNTH_CNT,-1) AS MON_BILL , B.TTL_INST_MNTH_CNT , B.RMN_INST_CNT , B.GRNT_INSR_MNGM_NO , A.BOND_SEQ_NO FROM MSP_BOND_SALE_DTL A , MSP_BOND_ASSET B WHERE 1 = 1 AND A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND B.BILL_YM = #{billYm} AND A.BOND_SEQ_NO = #{bondSeqNo} AND A.RTN_YM IS NULL
AND DECODE(B.UNPAY_ARRS_FEE_AMNT,0,'N','Y') = #{billArrAmtYn}
AND DECODE(B.ADJS_AMNT,0,'N','Y') = #{adjsAmtYn}
AND ( B.MID_PRFPAY_AMNT > 0 AND B.YET_PYMN_AMNT = 0 )
AND B.MID_PRFPAY_AMNT = 0
AND ( B.MID_PRFPAY_AMNT > 0 AND B.YET_PYMN_AMNT > 0 )
AND B.MID_PRFPAY_AMNT = 0
AND DECODE(B.INSR_BILL_AMNT,0,'N','Y') = #{insrBillYn}
ORDER BY B.GRNT_INSR_MNGM_NO

SELECT /* BondMgmtMapper.selectBondSaleCntrListEx */ B.CONTRACT_NUM , B.SUBSCRIBER_NO , B.SUB_LINK_NAME , FN_GET_CODENM('RCP001', B.CUSTOMER_TYPE) AS CUSTOMER_TYPE , DECODE(B.CUSTOMER_TYPE, 'I', SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN),0,6), '') AS USER_SSN , B.TAX_ID , B.SUB_ADR_PRIMARY_LN , F_GET_AGENT_NM(B.OPEN_AGNT_CD) AS OPEN_AGNT_CD , B.TTL_INST_AMNT , B.TTL_INST_MNTH_CNT , B.RMN_INST_CNT , TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(B.INST_STRT_DATE, 'YYYYMMDD'), 1)), 'YYYY-MM-DD') AS PAY_STRT_DT , TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(B.INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYY-MM-DD') AS PAY_END_DT , B.YET_PYMN_AMNT , A.BOND_SEQ_NO , A.GRNT_INSR_MNGM_NO FROM MSP_BOND_SALE_DTL A , MSP_BOND_ASSET B WHERE A.GRNT_INSR_MNGM_NO = B.GRNT_INSR_MNGM_NO AND A.RTN_YM IS NULL AND A.BOND_SEQ_NO = #{bondSeqNo} AND B.BILL_YM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SALE_YM,'YYYYMM'),-1),'YYYYMM')
AND (B.INSR_BILL_AMNT > 0 AND B.UNPAY_AMNT > 0)
AND (B.INSR_BILL_AMNT = 0 OR B.UNPAY_AMNT = 0)
AND B.GRNT_INSR_MNGM_NO = #{pSearchName}
AND B.CONTRACT_NUM = #{pSearchName}
AND B.SUBSCRIBER_NO = #{pSearchName}
AND B.SUB_LINK_NAME = #{pSearchName}

SELECT /* BondSaleMapper.selectBondSaleObjectListEx */ CONTRACT_NUM , SUB_LINK_NAME , GRNT_INSR_STAT_CHNG_RSN_CD , UNPAID_YN, TTL_INST_AMNT , TTL_INST_MNTH_CNT , MNT_INST_AMT, PAY_AMT, YET_PYMN_AMNT , RMN_INST_CNT , PAY_STRT_DT, PAY_END_DT, GRNT_INSR_MNGM_NO, TO_CHAR(TO_DATE(INST_STRT_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS INST_STRT_DATE, TO_CHAR(TO_DATE(INSR_TRMN_DATE,'YYYYMMDD'),'YYYY-MM-DD' ) AS INSR_TRMN_DATE, PYMN_CNT FROM (
SELECT CONTRACT_NUM , SUB_LINK_NAME , FN_GET_CODENM('BND1000', GRNT_INSR_STAT_CHNG_RSN_CD) AS GRNT_INSR_STAT_CHNG_RSN_CD , DECODE(UNPAY_ARRS_TMSCNT,0,'N','Y') AS UNPAID_YN, TTL_INST_AMNT , TTL_INST_MNTH_CNT , TRUNC(TTL_INST_AMNT / TTL_INST_MNTH_CNT,-1) AS MNT_INST_AMT, (TTL_INST_AMNT - YET_PYMN_AMNT ) AS PAY_AMT, YET_PYMN_AMNT , RMN_INST_CNT , TO_CHAR(ADD_MONTHS(TO_DATE(INST_STRT_DATE, 'YYYYMMDD'), 1), 'YYYY-MM')||'-01' AS PAY_STRT_DT, TO_CHAR(LAST_DAY(ADD_MONTHS(TO_DATE(INSR_TRMN_DATE, 'YYYYMMDD'), 1)), 'YYYY-MM-DD') AS PAY_END_DT, GRNT_INSR_MNGM_NO, INST_STRT_DATE, INSR_TRMN_DATE, MONTHS_BETWEEN(TO_DATE(BILL_YM, 'YYYYMM'), TO_DATE(SUBSTR(GRNT_INSR_MNGM_NO, 0, 6), 'YYYYMM')) - UNPAY_ARRS_TMSCNT AS PYMN_CNT FROM MSP_BOND_ASSET WHERE 1 = 1 AND MST_YN = 'Y' AND CHK_YN = 'N' AND YET_PYMN_AMNT > 0 AND GRNT_INSR_STAT_CHNG_RSN_CD IN ('A1','A3','A6','A9','Y1') AND GRNT_INSR_MNGM_NO NOT IN ( SELECT GRNT_INSR_MNGM_NO FROM MSP_BOND_SALE_DTL A, MSP_BOND_SALE_MST B WHERE A.BOND_SEQ_NO = B.BOND_SEQ_NO AND B.SALE_STAT_CD = 'A' ) ) WHERE 1 = 1
AND INST_STRT_DATE BETWEEN #{trgtStrtDt} AND #{trgtEndDt}
AND YET_PYMN_AMNT >= #{trgtRmnAmt}
AND RMN_INST_CNT >= #{trgtRmnCnt}
AND PYMN_CNT >= #{trgtPymCnt}
AND UNPAID_YN = #{trgtUnpaidYn}
ORDER BY INST_STRT_DATE DESC
